import React from 'react';
import { Platform, Alert } from 'react-native';
import { InAppUtils } from 'react-native-in-app-utils';
import InAppBilling from 'react-native-billing';

const ITEM_SKU = 'com.yourapp.productsku';

class PaymentModule extends React.Component {
  state = {
    canMakePayments: false,
  };

  componentDidMount() {
    if (Platform.OS === 'ios') {
      InAppUtils.canMakePayments(canMakePayments => {
        if(!canMakePayments){
          Alert.alert('Can not make payments');
        } else {
          this.setState({ canMakePayments });
        }
      });
    } else if (Platform.OS === 'android') {
      InAppBilling.close()
        .then(() => InAppBilling.open())
        .then(() => InAppBilling.loadDetails(ITEM_SKU))
        .then(() => InAppBilling.purchase(ITEM_SKU))
        .then(purchaseDetails => {
          this.setState({ canMakePayments: true });
        })
        .catch(err => {
          console.log(err);
          Alert.alert('Error', 'Can not make payments');
        });
    }
  }

  handlePurchase = () => {
    if(this.state.canMakePayments){
      if (Platform.OS === 'ios') {
        InAppUtils.purchaseProduct(ITEM_SKU, (error, response) => {
          if (response && response.productIdentifier) {
            Alert.alert('Thank you for your purchase!');
          } else if (error) {
            Alert.alert('Something went wrong');
          }
        });
      } else if (Platform.OS === 'android') {
        InAppBilling.close()
          .then(() => InAppBilling.open())
          .then(() => InAppBilling.purchase(ITEM_SKU))
          .then(purchaseDetails => {
            Alert.alert('Thank you for your purchase!');
          })
          .catch(err => {
            console.log(err);
          });
      }
    } else {
      Alert.alert('Can not make payments');
    }
  }

  render() {
    return <PaymentButton onPress={this.handlePurchase} />
  }
}

export default PaymentModule;